mapper.insert:

    SELECT NVL(MAX(SEQ), 0) + 1 FROM NMCP_DOC_RCV_URL_OTP WHERE RCV_URL_ID = #{rcvUrlId}

INSERT INTO NMCP_DOC_RCV_URL_OTP (
    RCV_URL_ID
    , SEQ
    , OTP
    , STATUS
    , ISSUE_DT
    , FAIL_CNT
    , CRET_ID
    , CRET_DT
) VALUES (
    #{rcvUrlId}
    , #{seq}
    , #{otp}
    , 'A'
    , SYSDATE
    , 0
    , 'MCP'
    , SYSDATE
)

INSERT INTO NMCP_DOC_RCV_LOG ( LOG_SEQ, DOC_RCV_ID, START_TIME, END_TIME, CONTENT_LENGTH, CREATE_AT )
VALUES (
    SQ_DOC_RCV_LOG.nextval
    , #{docRcvId}
    , TO_TIMESTAMP(#{startTime}, 'YYYY-MM-DD"T"HH24:MI:SS.FF3')
    , TO_TIMESTAMP(#{endTime}, 'YYYY-MM-DD"T"HH24:MI:SS.FF3')
    , #{contentLength}
    , SYSTIMESTAMP
)
